def merge_ranges(pairs):
    sorted_pairs = sorted(pairs, key=lambda x: x[0])
    merged = [sorted_pairs[0]]
    for pair in sorted_pairs[1:]:
        last = merged[-1]
        if last[1] >= pair[0]:
            last[1] = max(last[1], pair[1])
        else:
            merged.append(pair)
    return merged
